Stream<String> stream = List.of("a", "b").stream();
stream.forEach(System.out::println); // Terminal operation
// stream.count(); // THROWS IllegalStateException!

List<List<String>> nestedLists = List.of(List.of("A"), List.of("B"));
// map() results in Stream<List<String>>
// flatMap() results in Stream<String> containing "A", "B"
List<String> flat = nestedLists.stream()
    .flatMap(List::stream)
    .collect(Collectors.toList());

List<Integer> list = List.of(1, 2, 3, 4, 5);
list.stream()
    .filter(n -> { System.out.print("F"+n); return n % 2 == 0; })
    .map(n -> { System.out.print("M"+n); return n * 10; })
    .findFirst();
// Output: F1 F2 M2 (It never evaluates 3, 4, or 5!)

