// Infinite stream of random numbers
Stream.generate(Math::random).limit(5).forEach(System.out::println);

// Infinite sequence: 0, 2, 4, 6...
Stream.iterate(0, n -> n + 2).limit(5).forEach(System.out::println);

// ANTI-PATTERN: Side-effects in map/forEach
List<String> badResult = new ArrayList<>();
names.stream().forEach(n -> badResult.add(n.toUpperCase()));

// CORRECT: Pure functions
List<String> goodResult = names.stream()
    .map(String::toUpperCase)
    .collect(Collectors.toList());
